// モック用ファイル
export const mockLogin = async ({ userId, password }) => {
  // 疑似的な認証処理
  if (userId === 'test' && password === '1234') {
    return { success: true, userName: 'テストユーザ' }
  } else {
    return { success: false }
  }
}
